"use client";

import React, { useState, useMemo } from "react";
import { useConfig } from "@/context/ConfigContext";
import {
    DndContext,
    closestCenter,
    KeyboardSensor,
    PointerSensor,
    useSensor,
    useSensors,
} from '@dnd-kit/core';
import {
    arrayMove,
    SortableContext,
    sortableKeyboardCoordinates,
    verticalListSortingStrategy,
} from '@dnd-kit/sortable';
import { useSortable } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import { GripVertical, AlertCircle, ArrowDownAZ, ArrowUpZA, Edit2, RotateCcw } from "lucide-react";
import { Input } from "@/components/ui/input";

// Individual Sortable Item Component
function SortableCatalogItem({
    id,
    displayName,
    isEnabled,
    onToggle,
    onRename
}: {
    id: string,
    displayName: string,
    isEnabled: boolean,
    onToggle: (isEnabled: boolean) => void,
    onRename: (id: string, newName: string) => void
}) {
    const {
        attributes,
        listeners,
        setNodeRef,
        transform,
        transition,
        isDragging,
    } = useSortable({ id });

    const style = {
        transform: CSS.Transform.toString(transform),
        transition,
        zIndex: isDragging ? 10 : 1,
    };

    const [isEditing, setIsEditing] = useState(false);
    const [editValue, setEditValue] = useState(displayName);

    const handleRenameSubmit = () => {
        setIsEditing(false);
        if (editValue.trim() !== "" && editValue !== displayName) {
            onRename(id, editValue.trim());
        } else {
            setEditValue(displayName); // reset
        }
    };

    const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter') handleRenameSubmit();
        if (e.key === 'Escape') {
            setEditValue(displayName);
            setIsEditing(false);
        }
    };

    return (
        <div
            ref={setNodeRef}
            style={style}
            className={`group flex items-center gap-3 p-3 bg-neutral-900 border border-neutral-800 rounded-lg mb-2 ${isDragging ? "opacity-50 border-blue-500" : ""}`}
        >
            <button {...attributes} {...listeners} className="cursor-grab hover:text-white text-neutral-500" aria-label="Drag handle">
                <GripVertical className="h-4 w-4" />
            </button>
            <div className="flex-1 min-w-0">
                {isEditing ? (
                    <Input
                        value={editValue}
                        onChange={(e) => setEditValue(e.target.value)}
                        onBlur={handleRenameSubmit}
                        onKeyDown={handleKeyDown}
                        autoFocus
                        className="h-8 text-sm bg-neutral-950 border-blue-500 focus-visible:ring-1 focus-visible:ring-blue-500"
                    />
                ) : (
                    <div
                        className="flex-1 min-w-0 cursor-pointer p-1.5 -ml-1.5 rounded hover:bg-neutral-800/80 transition-colors border border-transparent hover:border-neutral-700"
                        onClick={() => setIsEditing(true)}
                        title="Click to rename"
                    >
                        <p className={`text-sm truncate font-medium ${!isEnabled ? "text-neutral-500 line-through" : "text-neutral-200"}`}>{displayName}</p>
                        {displayName !== id && <p className="text-[10px] text-neutral-500 truncate font-mono">{id}</p>}
                    </div>
                )}
            </div>
            <Switch
                checked={isEnabled}
                onCheckedChange={onToggle}
                className="data-[state=checked]:bg-blue-600"
            />
        </div>
    );
}

export function CatalogEditor() {
    const { initialValues, currentValues, updateValue, disabledCatalogs, toggleCatalog } = useConfig();

    // Try to find the catalog array
    const catalogsKey = currentValues["catalog_ordering"] ? "catalog_ordering" :
        currentValues["selected_catalogs"] ? "selected_catalogs" : null;

    const catalogItems: string[] = catalogsKey ? (currentValues[catalogsKey] || []) : [];

    // We keep a local state for sorting purely for UI reactivity, but sync it to context
    const [items, setItems] = useState(catalogItems);

    const customNames = currentValues["custom_catalog_names"] || {};

    // Sync state if external changes happen (though unlikely for this array)
    React.useEffect(() => {
        setItems(catalogItems);
    }, [JSON.stringify(catalogItems)]);

    const sensors = useSensors(
        useSensor(PointerSensor),
        useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates })
    );

    if (!catalogsKey || !Array.isArray(catalogItems)) {
        return (
            <div className="p-4 text-sm text-yellow-500 bg-yellow-500/10 border border-yellow-500/20 rounded-md flex gap-2 items-start">
                <AlertCircle className="w-4 h-4 mt-0.5 shrink-0" />
                <span>Could not locate a recognizable 'catalog_ordering' or 'selected_catalogs' array in the root. </span>
            </div>
        );
    }

    const handleDragEnd = (event: any) => {
        const { active, over } = event;
        if (active.id !== over.id) {
            const oldIndex = items.indexOf(active.id);
            const newIndex = items.indexOf(over.id);
            const newArray = arrayMove(items, oldIndex, newIndex);

            setItems(newArray);
            updateValue([catalogsKey], newArray);
        }
    };

    const sortAZ = () => {
        const sorted = [...items].sort();
        setItems(sorted);
        updateValue([catalogsKey], sorted);
    };

    const sortZA = () => {
        const sorted = [...items].sort().reverse();
        setItems(sorted);
        updateValue([catalogsKey], sorted);
    };

    const resetOrder = () => {
        const orig = initialValues[catalogsKey];
        if (orig && Array.isArray(orig)) {
            setItems(orig);
            updateValue([catalogsKey], orig);
        }
    };

    const enableAll = () => {
        items.forEach(id => toggleCatalog(id, true));
    };
    const disableAll = () => {
        items.forEach(id => toggleCatalog(id, false));
    };

    const handleRename = (id: string, newName: string) => {
        const newNamesMap = { ...customNames, [id]: newName };
        updateValue(["custom_catalog_names"], newNamesMap);
    };

    return (
        <div className="space-y-4">
            <p className="text-sm text-neutral-400">
                Drag and drop to reorder catalogs. Disabling a catalog here will strip it from the final JSON everywhere it is referenced.
            </p>

            <div className="flex flex-wrap items-center gap-2 mb-4 bg-neutral-900/50 p-2 rounded-lg border border-neutral-800">
                <Button variant="outline" size="sm" onClick={sortAZ} className="h-8 text-xs border-neutral-700 hover:bg-neutral-800">
                    <ArrowDownAZ className="w-4 h-4 mr-2" /> A-Z
                </Button>
                <Button variant="outline" size="sm" onClick={sortZA} className="h-8 text-xs border-neutral-700 hover:bg-neutral-800">
                    <ArrowUpZA className="w-4 h-4 mr-2" /> Z-A
                </Button>
                <Button variant="outline" size="sm" onClick={resetOrder} className="h-8 text-xs border-neutral-700 hover:bg-neutral-800">
                    <RotateCcw className="w-4 h-4 mr-2" /> Reset Order
                </Button>
                <div className="w-px h-5 bg-neutral-800 mx-2" />
                <Button variant="ghost" size="sm" onClick={enableAll} className="h-8 text-xs text-blue-400 hover:text-blue-300">Enable All</Button>
                <Button variant="ghost" size="sm" onClick={disableAll} className="h-8 text-xs text-neutral-500 hover:text-neutral-400">Disable All</Button>
            </div>

            <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
                <SortableContext items={items} strategy={verticalListSortingStrategy}>
                    <div className="space-y-0.5 max-h-[500px] overflow-y-auto pr-2 custom-scrollbar">
                        {items.map((id) => (
                            <SortableCatalogItem
                                key={id}
                                id={id}
                                displayName={customNames[id] || id}
                                isEnabled={!disabledCatalogs.has(id)}
                                onToggle={(active) => toggleCatalog(id, active)}
                                onRename={handleRename}
                            />
                        ))}
                    </div>
                </SortableContext>
            </DndContext>
        </div>
    );
}
